//! fat-station-memo — fat-station kernel + the `/memo/*` HTTP knob set.
//!
//! Why this exists
//! ----------------
//! `bin/fat-station.rs` serves the layer-station wire contract (/embed,
//! /forward, /lm-head, /cobordism-*) but never exposes the
//! `MatVecMemo` (Death #1, ER=EPR teleportation cache) to the host.
//! The cache defaults to `enabled=false`; the only way to turn it on
//! today is to recompile or to use the wasm worker which DOES expose
//! `/memo/configure`, `/memo/stats`, `/memo/drift`, `/memo/probe-drift`,
//! `/memo/clear`, `/memo/selftest` (see
//! `apps/distributed-inference-worker/src/index.ts`).
//!
//! This bin runs the SAME inference routes as fat-station and ALSO
//! mirrors the wasm worker's six `/memo/*` routes byte-for-byte so the
//! pneuma host can flip the cache per-session against a native station.
//! `fat-station.rs` is intentionally NOT touched — the routes live here.
//!
//! ARCHITECTURAL STATUS:
//!   - Hot path: SAME `NativeLlamaPipeline` kernel as fat-station.
//!   - Wire helpers: copied from fat-station.rs (they are not `pub`).
//!     If/when fat-station is refactored to share wire helpers via the
//!     library crate, this bin should slim down to import them.
//!   - Memo wire format: mirrors `apps/distributed-inference-worker/
//!     src/index.ts:980-1158, 1330-1464` exactly so a single TS client
//!     (`distributed-inference-host/src/memo-client.ts`) speaks both
//!     the wasm worker and this bin without branching.
//!
//! Wire contract additions over fat-station
//! ----------------------------------------
//! POST /memo/configure
//!     body:  JSON `{ enabled?: bool, tau_squared?: number, max_entries?: number }`
//!     reply: JSON `{ configured: true, stats: { hits, misses, evictions } }`
//! GET  /memo/stats
//!     reply: JSON `{ hits, misses, evictions, total, hit_rate }`
//! GET  /memo/drift?threshold=N        (or ?luminary_threshold_q12=N)
//!     reply: JSON Pisot-drift histogram + scope note (see handler doc)
//! POST /memo/probe-drift
//!     body:  raw f32 LE bytes
//!     reply: JSON `{ drift, drift_finite, norm, norm_squared, length, ... }`
//! POST /memo/clear
//!     reply: JSON `{ cleared: true }`
//! POST /memo/selftest
//!     body:  JSON `{ steps?, hidden_dim?, tau_squared?, max_entries?, layer? }`
//!     reply: JSON `{ cold_ms, warm1_ms, warm2_ms, stats_after_fill,
//!                    stats_final, drift, hidden_dim, steps, tau_squared, layer }`
//!
//! CLI: same as fat-station.
//!   fat-station-memo --knot PATH --port N --role {entry|mid|exit|both|cobordism}
//!                    --layers START..END
//!                    [--vocab START..END]   (cobordism only)
//!
//! Honest scope note
//! -----------------
//! The selftest pass is only meaningful when this station owns layer 0
//! (i.e., role=entry|both with --layers 0..N). For mid/exit stations the
//! selftest will accept a `layer` body field pointing at one of the
//! station's resident layers (default: `--layers.0`). If neither the
//! station nor the override owns the requested layer, the selftest 404s.

use std::sync::{Arc, Mutex};

use distributed_inference::matvec_memo;
use distributed_inference::model::NativeLlamaPipeline;

const NATIVE_BATCH_CAPACITY: usize = 8;
use tiny_http::{Header, Method, Request, Response, Server};

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Role {
    Entry,
    Mid,
    Exit,
    Both,
    Cobordism,
}

impl Role {
    fn parse(s: &str) -> Result<Self, String> {
        match s.to_lowercase().as_str() {
            "entry" => Ok(Role::Entry),
            "mid" => Ok(Role::Mid),
            "exit" => Ok(Role::Exit),
            "both" => Ok(Role::Both),
            "cobordism" => Ok(Role::Cobordism),
            other => Err(format!(
                "--role must be entry|mid|exit|both|cobordism (got '{}')",
                other
            )),
        }
    }
    fn as_str(self) -> &'static str {
        match self {
            Role::Entry => "entry",
            Role::Mid => "mid",
            Role::Exit => "exit",
            Role::Both => "both",
            Role::Cobordism => "cobordism",
        }
    }
}

#[derive(Debug)]
struct Cli {
    knot: String,
    port: u16,
    role: Role,
    layers: (usize, usize),
    vocab: Option<(usize, usize)>,
}

fn parse_range(arg: &str, name: &str) -> Result<(usize, usize), String> {
    let sep = if arg.contains("..") { ".." } else { ":" };
    let (a, b) = arg
        .split_once(sep)
        .ok_or_else(|| format!("{}: expected 'start..end' (got '{}')", name, arg))?;
    let start: usize = a
        .parse()
        .map_err(|e| format!("{}: bad start '{}': {}", name, a, e))?;
    let end: usize = b
        .parse()
        .map_err(|e| format!("{}: bad end '{}': {}", name, b, e))?;
    if end < start {
        return Err(format!(
            "{}: end must be >= start ({} < {})",
            name, end, start
        ));
    }
    Ok((start, end))
}

fn parse_cli() -> Result<Cli, String> {
    let mut args = std::env::args().skip(1);
    let mut knot: Option<String> = None;
    let mut port: u16 = 8000;
    let mut role: Option<Role> = None;
    let mut layers: Option<(usize, usize)> = None;
    let mut vocab: Option<(usize, usize)> = None;
    while let Some(a) = args.next() {
        match a.as_str() {
            "--knot" => {
                knot = Some(args.next().ok_or("--knot requires a value")?);
            }
            "--port" => {
                let v = args.next().ok_or("--port requires a value")?;
                port = v.parse().map_err(|e| format!("--port: {}", e))?;
            }
            "--role" => {
                let v = args.next().ok_or("--role requires a value")?;
                role = Some(Role::parse(&v)?);
            }
            "--layers" => {
                let v = args.next().ok_or("--layers requires a value")?;
                layers = Some(parse_range(&v, "--layers")?);
            }
            "--vocab" => {
                let v = args.next().ok_or("--vocab requires a value")?;
                vocab = Some(parse_range(&v, "--vocab")?);
            }
            "--help" | "-h" => {
                print_usage();
                std::process::exit(0);
            }
            other => return Err(format!("unknown arg: {}", other)),
        }
    }
    let knot = knot.ok_or("--knot is required")?;
    let role = role.ok_or("--role is required")?;
    let layers = layers.unwrap_or((0, 0));
    if role == Role::Cobordism && vocab.is_none() {
        return Err("--vocab is required when --role=cobordism".to_string());
    }
    Ok(Cli {
        knot,
        port,
        role,
        layers,
        vocab,
    })
}

fn print_usage() {
    eprintln!(
        "fat-station-memo --knot PATH --port N --role {{entry|mid|exit|both|cobordism}} \\\n  \
         --layers START..END [--vocab START..END]\n\n\
         Adds the /memo/* knob set on top of the fat-station wire contract.\n\
         See bin/fat-station.rs for the inference route docs."
    );
}

// ─────────────────────────────────────────────────────────────────────
// Wire helpers (copied from fat-station.rs — they aren't `pub`)
// ─────────────────────────────────────────────────────────────────────

fn header_value(req: &Request, name: &str) -> Option<String> {
    let target = name.to_ascii_lowercase();
    for h in req.headers() {
        if h.field.as_str().as_str().to_ascii_lowercase() == target {
            return Some(h.value.as_str().to_string());
        }
    }
    None
}

fn parse_usize_header(req: &Request, name: &str) -> Result<usize, String> {
    let v = header_value(req, name).ok_or_else(|| format!("missing header: {}", name))?;
    v.parse::<usize>()
        .map_err(|e| format!("{}={:?}: {}", name, v, e))
}

fn parse_layer_range_header(req: &Request) -> Result<(usize, usize), String> {
    let raw = header_value(req, "X-Layer-Range")
        .ok_or_else(|| "missing header: X-Layer-Range".to_string())?;
    let (a, b) = raw
        .split_once('-')
        .ok_or_else(|| format!("X-Layer-Range='{}': expected 'start-end'", raw))?;
    let s: usize = a
        .parse()
        .map_err(|e| format!("X-Layer-Range start: {}", e))?;
    let e: usize = b.parse().map_err(|e| format!("X-Layer-Range end: {}", e))?;
    Ok((s, e))
}

fn read_body(req: &mut Request) -> Result<Vec<u8>, String> {
    let mut buf = Vec::new();
    req.as_reader()
        .read_to_end(&mut buf)
        .map_err(|e| format!("read body: {}", e))?;
    Ok(buf)
}

fn body_to_f32(body: &[u8]) -> Result<Vec<f32>, String> {
    if !body.len().is_multiple_of(4) {
        return Err(format!(
            "body length {} not a multiple of 4 (expected packed f32)",
            body.len()
        ));
    }
    let n = body.len() / 4;
    let mut out = vec![0.0f32; n];
    for i in 0..n {
        let off = i * 4;
        let word = u32::from_le_bytes([body[off], body[off + 1], body[off + 2], body[off + 3]]);
        out[i] = f32::from_bits(word);
    }
    Ok(out)
}

fn body_to_u32(body: &[u8]) -> Result<Vec<u32>, String> {
    if !body.len().is_multiple_of(4) {
        return Err(format!(
            "body length {} not a multiple of 4 (expected packed u32)",
            body.len()
        ));
    }
    let n = body.len() / 4;
    let mut out = vec![0u32; n];
    for i in 0..n {
        let off = i * 4;
        out[i] = u32::from_le_bytes([body[off], body[off + 1], body[off + 2], body[off + 3]]);
    }
    Ok(out)
}

fn f32_to_body(arr: &[f32]) -> Vec<u8> {
    let mut out = Vec::with_capacity(arr.len() * 4);
    for v in arr {
        out.extend_from_slice(&v.to_bits().to_le_bytes());
    }
    out
}

fn header(name: &str, value: &str) -> Header {
    Header::from_bytes(name.as_bytes(), value.as_bytes()).expect("static header bytes valid")
}

fn octet_response(
    bytes: Vec<u8>,
    request_id: &str,
    compute_ms: u128,
) -> Response<std::io::Cursor<Vec<u8>>> {
    Response::from_data(bytes)
        .with_status_code(200)
        .with_header(header("Content-Type", "application/octet-stream"))
        .with_header(header("X-Request-Id", request_id))
        .with_header(header("X-Compute-Ms", &compute_ms.to_string()))
}

fn json_response(json: String, status: u16) -> Response<std::io::Cursor<Vec<u8>>> {
    Response::from_string(json)
        .with_status_code(status)
        .with_header(header("Content-Type", "application/json"))
}

fn error_response(msg: &str, status: u16) -> Response<std::io::Cursor<Vec<u8>>> {
    eprintln!("[fat-station-memo] error {}: {}", status, msg);
    let body = format!("{{\"error\":{:?}}}", msg);
    json_response(body, status)
}

fn panic_payload(p: &Box<dyn std::any::Any + Send>) -> String {
    if let Some(s) = p.downcast_ref::<String>() {
        s.clone()
    } else if let Some(s) = p.downcast_ref::<&'static str>() {
        s.to_string()
    } else {
        "<non-string panic payload>".to_string()
    }
}

// ─────────────────────────────────────────────────────────────────────
// Inference handlers (mirror fat-station.rs)
// ─────────────────────────────────────────────────────────────────────

struct Station {
    pipeline: Mutex<NativeLlamaPipeline>,
    role: Role,
    layers: (usize, usize),
    vocab: Option<(usize, usize)>,
    vocab_size: usize,
    hidden_dim: usize,
}

fn handle_health(station: &Station, req: Request) {
    let layers = format!("{}-{}", station.layers.0, station.layers.1);
    let vocab = match station.vocab {
        Some((s, e)) => format!("{}-{}", s, e),
        None => "all".to_string(),
    };
    let body = format!(
        "{{\"status\":\"ok\",\"role\":\"{}\",\"layers\":\"{}\",\"vocab\":\"{}\",\"vocab_size\":{},\"hidden_dim\":{},\"memo_routes\":true}}",
        station.role.as_str(),
        layers,
        vocab,
        station.vocab_size,
        station.hidden_dim,
    );
    let _ = req.respond(json_response(body, 200));
}

fn handle_embed(station: &Station, mut req: Request) {
    if !matches!(station.role, Role::Entry | Role::Both) {
        let _ = req.respond(error_response(
            &format!("/embed not available on role={}", station.role.as_str()),
            404,
        ));
        return;
    }
    let request_id = header_value(&req, "X-Request-Id").unwrap_or_else(|| "no-id".to_string());
    let start_pos = match parse_usize_header(&req, "X-Position") {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let body = match read_body(&mut req) {
        Ok(b) => b,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let tokens = match body_to_u32(&body) {
        Ok(t) => t,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let t0 = std::time::Instant::now();
    let result = {
        let mut p = station.pipeline.lock().unwrap();
        std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            p.embed_chunk(&tokens, start_pos)
        }))
    };
    match result {
        Ok(Ok(out)) => {
            let _ = req.respond(octet_response(
                f32_to_body(&out),
                &request_id,
                t0.elapsed().as_millis(),
            ));
        }
        Ok(Err(e)) => {
            let _ = req.respond(error_response(&format!("embed error: {}", e), 500));
        }
        Err(e) => {
            let _ = req.respond(error_response(
                &format!("embed panicked: {:?}", panic_payload(&e)),
                500,
            ));
        }
    }
}

fn handle_forward(station: &Station, mut req: Request) {
    if matches!(station.role, Role::Cobordism) {
        let _ = req.respond(error_response(
            "/forward not available on cobordism shard",
            404,
        ));
        return;
    }
    let request_id = header_value(&req, "X-Request-Id").unwrap_or_else(|| "no-id".to_string());
    let start_pos = match parse_usize_header(&req, "X-Position") {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let seq_len = match parse_usize_header(&req, "X-Sequence-Length") {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let layer_range = match parse_layer_range_header(&req) {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let body = match read_body(&mut req) {
        Ok(b) => b,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let residual = match body_to_f32(&body) {
        Ok(r) => r,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    if seq_len == 0 || seq_len > NATIVE_BATCH_CAPACITY {
        let _ = req.respond(error_response(
            &format!(
                "seq_len {} out of range (0, {}]",
                seq_len, NATIVE_BATCH_CAPACITY
            ),
            400,
        ));
        return;
    }
    let t0 = std::time::Instant::now();
    let result = {
        let mut p = station.pipeline.lock().unwrap();
        std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            p.forward_range_chunk(&residual, layer_range.0, layer_range.1, start_pos, seq_len)
        }))
    };
    match result {
        Ok(Ok(out)) => {
            let _ = req.respond(octet_response(
                f32_to_body(&out),
                &request_id,
                t0.elapsed().as_millis(),
            ));
        }
        Ok(Err(e)) => {
            let _ = req.respond(error_response(&format!("forward error: {}", e), 500));
        }
        Err(e) => {
            let _ = req.respond(error_response(
                &format!("forward panicked: {:?}", panic_payload(&e)),
                500,
            ));
        }
    }
}

