fn handle_decode_next(station: &Station, req: Request) {
    if station.role != Role::Both {
        let _ = req.respond(error_response(
            &format!(
                "/decode-next only available on role=both (got role={})",
                station.role.as_str()
            ),
            404,
        ));
        return;
    }
    let token = match parse_usize_header(&req, "X-Token") {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    if token > u32::MAX as usize {
        let _ = req.respond(error_response("X-Token exceeds u32 range", 400));
        return;
    }
    let pos = match parse_usize_header(&req, "X-Position") {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let t0 = std::time::Instant::now();
    let result = {
        let mut p = station.pipeline.lock().unwrap();
        std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            p.decode_next_fast_argmax(token as u32, pos)
        }))
    };
    match result {
        Ok(Ok((token_id, _forward_us, _logit_us))) => {
            let resp = serde_json::json!({
                "token_id": token_id,
                "elapsed_ms": t0.elapsed().as_millis(),
            });
            let _ = req.respond(json_response(resp.to_string(), 200));
        }
        Ok(Err(e)) => {
            let _ = req.respond(error_response(&format!("decode_next error: {}", e), 500));
        }
        Err(e) => {
            let _ = req.respond(error_response(
                &format!("decode_next panicked: {:?}", panic_payload(&e)),
                500,
            ));
        }
    }
}

