/// Tiny JSON parser slice. tiny_http has no JSON helper; we DON'T pull in
/// serde_json everywhere because the bin already depends on it through
/// the lib crate (knot header sniff). Use `serde_json::Value`.
fn parse_json_body(body: &[u8]) -> Result<serde_json::Value, String> {
    let s = std::str::from_utf8(body).map_err(|e| format!("body not UTF-8: {}", e))?;
    serde_json::from_str::<serde_json::Value>(s).map_err(|e| format!("body not JSON: {}", e))
}

fn handle_memo_configure(station: &Station, mut req: Request) {
    let body_bytes = match read_body(&mut req) {
        Ok(b) => b,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    if body_bytes.is_empty() {
        let _ = req.respond(error_response("memo/configure: empty body", 400));
        return;
    }
    let body = match parse_json_body(&body_bytes) {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&format!("memo/configure: {}", e), 400));
            return;
        }
    };
    let mut p = station.pipeline.lock().unwrap();
    if let Some(b) = body.get("enabled").and_then(|v| v.as_bool()) {
        p.memo.set_enabled(b);
    }
    if let Some(t) = body.get("tau_squared").and_then(|v| v.as_f64()) {
        if t >= 0.0 {
            p.memo.set_tau_squared(t as f32);
        }
    }
    if let Some(n) = body.get("max_entries").and_then(|v| v.as_u64()) {
        if n >= 1 {
            p.memo.set_max_entries(n as usize);
        }
    }
    let (h, m, e) = p.memo.stats();
    drop(p);
    let json = format!(
        "{{\"configured\":true,\"stats\":{{\"hits\":{},\"misses\":{},\"evictions\":{}}}}}",
        h, m, e
    );
    let _ = req.respond(json_response(json, 200));
}

fn handle_memo_stats(station: &Station, req: Request) {
    let p = station.pipeline.lock().unwrap();
    let (h, m, e) = p.memo.stats();
    drop(p);
    let total = h + m;
    let hit_rate = if total > 0 {
        (h as f64 / total as f64 * 10000.0).round() / 10000.0
    } else {
        0.0
    };
    let json = format!(
        "{{\"hits\":{},\"misses\":{},\"evictions\":{},\"total\":{},\"hit_rate\":{:.4}}}",
        h, m, e, total, hit_rate
    );
    let _ = req.respond(json_response(json, 200));
}

/// `/memo/drift` — accepts either `?threshold=N` (f32) or
/// `?luminary_threshold_q12=N` (q12 fixed-point, mirrors the wasm worker
/// boundary). f32 wins if both are present. Default = 0.5 (just above
/// the surrogate minimum ≈ 0.345).
fn handle_memo_drift(station: &Station, req: Request) {
    let raw_url = req.url().to_string();
    let (path, query) = match raw_url.split_once('?') {
        Some((p, q)) => (p.to_string(), q.to_string()),
        None => (raw_url.clone(), String::new()),
    };
    let _ = path; // silence
    let mut threshold: f32 = 0.5;
    for kv in query.split('&') {
        if let Some((k, v)) = kv.split_once('=') {
            if k == "threshold" {
                if let Ok(f) = v.parse::<f32>() {
                    if f.is_finite() && f > 0.0 {
                        threshold = f;
                    }
                }
            } else if k == "luminary_threshold_q12" {
                if let Ok(q) = v.parse::<u32>() {
                    threshold = (q as f32) / 4096.0;
                }
            }
        }
    }
    let p = station.pipeline.lock().unwrap();
    let (luminary, total, finite, dmin, dmean, dmax) = p.memo.drift_summary(threshold);
    drop(p);
    let nan_count = total.saturating_sub(finite);
    let lum_frac = if finite > 0 {
        (luminary as f64 / finite as f64 * 10000.0).round() / 10000.0
    } else {
        0.0
    };
    let r6 = |v: f32| -> f64 {
        if !v.is_finite() {
            0.0
        } else {
            (v as f64 * 1_000_000.0).round() / 1_000_000.0
        }
    };
    let json = format!(
        "{{\"luminary\":{},\"total\":{},\"finite\":{},\"nan_count\":{},\
         \"luminary_fraction\":{:.4},\"luminary_threshold\":{:.6},\
         \"drift_min\":{:.6},\"drift_mean\":{:.6},\"drift_max\":{:.6},\
         \"surrogate_minimum\":0.3455,\
         \"note\":\"f32 surrogate; Lean witness on integer Lucas pairs (PisotMitosisManifold.lean:47).\"}}",
        luminary,
        total,
        finite,
        nan_count,
        lum_frac,
        threshold as f64,
        r6(dmin),
        r6(dmean),
        r6(dmax),
    );
    let _ = req.respond(json_response(json, 200));
}

fn handle_memo_probe_drift(_station: &Station, mut req: Request) {
    let body = match read_body(&mut req) {
        Ok(b) => b,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    if body.is_empty() || body.len() % 4 != 0 {
        let _ = req.respond(error_response(
            &format!(
                "probe-drift: body must be non-empty f32 (got {} bytes)",
                body.len()
            ),
            400,
        ));
        return;
    }
    let f = match body_to_f32(&body) {
        Ok(v) => v,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let drift = matvec_memo::pisot_drift(&f);
    let mut norm_sq = 0.0_f64;
    for v in &f {
        norm_sq += (*v as f64) * (*v as f64);
    }
    let norm = norm_sq.sqrt();
    let drift_finite = drift.is_finite();
    let drift_str = if drift_finite {
        format!("{}", drift)
    } else {
        "null".to_string()
    };
    let json = format!(
        "{{\"drift\":{},\"drift_finite\":{},\"norm\":{},\"norm_squared\":{},\
         \"length\":{},\"surrogate_minimum\":0.3455,\
         \"formula\":\"|||x||^2 - phi*||x|| + 1|\"}}",
        drift_str,
        drift_finite,
        norm,
        norm_sq,
        f.len(),
    );
    let _ = req.respond(json_response(json, 200));
}

fn handle_memo_clear(station: &Station, req: Request) {
    {
        let mut p = station.pipeline.lock().unwrap();
        p.memo.clear();
    }
    let _ = req.respond(json_response("{\"cleared\":true}".to_string(), 200));
}

/// In-process cold/warm memo bench. See doc on
/// apps/distributed-inference-worker/src/index.ts:1330 for the rationale
/// (worker-side isolate rotation makes cross-request bench numbers lie;
/// here we bench in one handler so memo state persists across kernel
/// calls). On native this constraint doesn't strictly bind, but keeping
/// the same self-test endpoint means the host can use one validation
/// path for both worker and native stations.
fn handle_memo_selftest(station: &Station, mut req: Request) {
    if !matches!(station.role, Role::Entry | Role::Both) {
        let _ = req.respond(error_response(
            &format!(
                "/memo/selftest requires role=entry|both (got role={}, layers=[{},{}))",
                station.role.as_str(),
                station.layers.0,
                station.layers.1
            ),
            404,
        ));
        return;
    }
    if station.layers.0 != 0 {
        let _ = req.respond(error_response(
            &format!(
                "/memo/selftest requires layer 0 to be local (station owns [{}, {}))",
                station.layers.0, station.layers.1
            ),
            404,
        ));
        return;
    }
    let body_bytes = match read_body(&mut req) {
        Ok(b) => b,
        Err(e) => {
            let _ = req.respond(error_response(&e, 400));
            return;
        }
    };
    let body = if body_bytes.is_empty() {
        serde_json::Value::Object(serde_json::Map::new())
    } else {
        match parse_json_body(&body_bytes) {
            Ok(v) => v,
            Err(e) => {
                let _ = req.respond(error_response(&format!("memo/selftest: {}", e), 400));
                return;
            }
        }
    };
    let steps = body
        .get("steps")
        .and_then(|v| v.as_u64())
        .filter(|n| *n >= 1)
        .unwrap_or(8) as usize;
    // Honest scope: the body's `hidden_dim` field exists for wire parity
    // with the wasm worker, but the kernel expects exactly
    // `config.hidden_dim` floats per token. We accept the override only
    // if it MATCHES the station's hidden_dim; otherwise we silently fall
    // back so selftest can't OOB the kernel.
    let hidden_dim_override = body
        .get("hidden_dim")
        .and_then(|v| v.as_u64())
        .filter(|n| *n > 0);
    let hidden_dim = match hidden_dim_override {
        Some(n) if n as usize == station.hidden_dim => n as usize,
        _ => station.hidden_dim,
    };
    let tau_squared = body
        .get("tau_squared")
        .and_then(|v| v.as_f64())
        .filter(|f| *f >= 0.0)
        .unwrap_or(1e-3) as f32;
    let max_entries = body
        .get("max_entries")
        .and_then(|v| v.as_u64())
        .filter(|n| *n >= 1);
    let layer = body
        .get("layer")
        .and_then(|v| v.as_u64())
        .map(|n| n as usize)
        .unwrap_or(station.layers.0);

    // Deterministic Mulberry32 — same seed as the wasm worker so
    // cold/warm passes are bit-comparable across stations.
    let seed: u32 = 0xA0E0_1234;
    let mut s: u32 = seed;
    let mut next = || -> f32 {
        s = s.wrapping_add(0x6D2B79F5);
        let mut t = s;
        t = (t ^ (t >> 15)).wrapping_mul(t | 1);
        t ^= t.wrapping_add((t ^ (t >> 7)).wrapping_mul(t | 61));
        let bits = t ^ (t >> 14);
        (bits as f32 / 4_294_967_296.0_f32) * 2.0 - 1.0
    };
    let residual: Vec<f32> = (0..hidden_dim).map(|_| next()).collect();

    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        let mut p = station.pipeline.lock().unwrap();
        if let Some(n) = max_entries {
            p.memo.set_max_entries(n as usize);
        }
        let start_pos = 0;
        let seq_len = 1;
        let mut cold_ms: Vec<u128> = Vec::with_capacity(steps);
        let mut warm1_ms: Vec<u128> = Vec::with_capacity(steps);
        let mut warm2_ms: Vec<u128> = Vec::with_capacity(steps);

        let run_once = |p: &mut NativeLlamaPipeline| -> Result<u128, String> {
            let t0 = std::time::Instant::now();
            p.forward_range_attn_chunk(&residual, layer, start_pos, seq_len, true)
                .map_err(|e| format!("attn: {}", e))?;
            p.forward_range_ffn_gate_chunk(layer, seq_len)
                .map_err(|e| format!("ffn_gate: {}", e))?;
            p.forward_range_ffn_up_chunk(layer, seq_len)
                .map_err(|e| format!("ffn_up: {}", e))?;
            let _ = p
                .forward_range_ffn_down_chunk(layer, seq_len, false)
                .map_err(|e| format!("ffn_down: {}", e))?;
            Ok(t0.elapsed().as_millis())
        };

        // Cold.
        p.memo.clear();
        p.memo.set_enabled(false);
        for _ in 0..steps {
            cold_ms.push(run_once(&mut p)?);
        }
        // Warm fill.
        p.memo.clear();
        p.memo.set_enabled(true);
        p.memo.set_tau_squared(tau_squared);
        for _ in 0..steps {
            warm1_ms.push(run_once(&mut p)?);
        }
        let (fh, fm, fe) = p.memo.stats();
        // Warm rerun.
        for _ in 0..steps {
            warm2_ms.push(run_once(&mut p)?);
        }
        let (h, m, e) = p.memo.stats();
        let (lum, total, finite, dmin, dmean, dmax) = p.memo.drift_summary(0.5);
        Ok::<_, String>((
            cold_ms, warm1_ms, warm2_ms, fh, fm, fe, h, m, e, lum, total, finite, dmin, dmean, dmax,
        ))
    }));

    let json = match result {
        Ok(Ok((cold, w1, w2, fh, fm, fe, h, m, e, lum, total, finite, dmin, dmean, dmax))) => {
            let arr = |v: &[u128]| -> String {
                let parts: Vec<String> = v.iter().map(|x| x.to_string()).collect();
                format!("[{}]", parts.join(","))
            };
            let r6 = |v: f32| -> f64 {
                if !v.is_finite() {
                    0.0
                } else {
                    (v as f64 * 1_000_000.0).round() / 1_000_000.0
                }
            };
            format!(
                "{{\"cold_ms\":{cold},\"warm1_ms\":{w1},\"warm2_ms\":{w2},\
                 \"stats_after_fill\":{{\"hits\":{fh},\"misses\":{fm},\"evictions\":{fe}}},\
                 \"stats_final\":{{\"hits\":{h},\"misses\":{m},\"evictions\":{e}}},\
                 \"drift\":{{\"luminary\":{lum},\"total\":{total},\"finite\":{finite},\
                 \"drift_min\":{dmin:.6},\"drift_mean\":{dmean:.6},\"drift_max\":{dmax:.6},\
                 \"luminary_threshold\":0.5}},\
                 \"hidden_dim\":{hd},\"steps\":{steps},\"tau_squared\":{tau},\"layer\":{layer}}}",
                cold = arr(&cold),
                w1 = arr(&w1),
                w2 = arr(&w2),
                fh = fh,
                fm = fm,
                fe = fe,
                h = h,
                m = m,
                e = e,
                lum = lum,
                total = total,
                finite = finite,
                dmin = r6(dmin),
                dmean = r6(dmean),
                dmax = r6(dmax),
                hd = hidden_dim,
                steps = steps,
                tau = tau_squared,
                layer = layer,
            )
        }
        Ok(Err(e)) => {
            let _ = req.respond(error_response(&format!("memo/selftest failed: {}", e), 500));
            return;
        }
        Err(p) => {
            let _ = req.respond(error_response(
                &format!("memo/selftest panicked: {:?}", panic_payload(&p)),
                500,
            ));
            return;
        }
    };
    let _ = req.respond(json_response(json, 200));
}

// ─────────────────────────────────────────────────────────────────────
// main
// ─────────────────────────────────────────────────────────────────────

fn main() {
    let cli = match parse_cli() {
        Ok(c) => c,
        Err(e) => {
            eprintln!("ERROR: {}\n", e);
            print_usage();
            std::process::exit(2);
        }
    };

    eprintln!(
        "[fat-station-memo] booting role={} layers=[{},{}) port={} knot={}",
        cli.role.as_str(),
        cli.layers.0,
        cli.layers.1,
        cli.port,
        cli.knot
    );

    let t_boot = std::time::Instant::now();
    let pipeline = NativeLlamaPipeline::new(cli.knot.clone(), false, 0.9);
    eprintln!(
        "[fat-station-memo] pipeline ready in {} ms",
        t_boot.elapsed().as_millis()
    );
    // Read dims from the loaded pipeline. sniff_dims() on an HTTP knot URL
    // falls back to qwen-coder defaults (151_936 / 3584) and breaks openai-server.
    let vocab_size = pipeline.vocab_size();
    let hidden_dim = pipeline.hidden_dim();
    eprintln!(
        "[fat-station-memo] dims: vocab_size={} hidden_dim={}",
        vocab_size, hidden_dim
    );

    let station = Arc::new(Station {
        pipeline: Mutex::new(pipeline),
        role: cli.role,
        layers: cli.layers,
        vocab: cli.vocab,
        vocab_size,
        hidden_dim,
    });

    let bind = format!("127.0.0.1:{}", cli.port);
    let server = match Server::http(&bind) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("ERROR: bind {}: {}", bind, e);
            std::process::exit(3);
        }
    };
    eprintln!(
        "[fat-station-memo] listening on http://{}  (memo routes wired)",
        bind
    );

    for req in server.incoming_requests() {
        let st = Arc::clone(&station);
        std::thread::spawn(move || {
            let path = req.url().to_string();
            let method = req.method().clone();
            let path_only = path.split('?').next().unwrap_or(&path).to_string();
            match (&method, path_only.as_str()) {
                (Method::Get, "/health") => handle_health(&st, req),
                (Method::Post, "/embed") => handle_embed(&st, req),
                (Method::Post, "/forward") => handle_forward(&st, req),
                (Method::Post, "/lm-head") => handle_lm_head(&st, req),
                (Method::Post, "/sample-next") => handle_sample_next(&st, req),
                (Method::Post, "/decode-next") => handle_decode_next(&st, req),
                (Method::Post, "/memo/configure") => handle_memo_configure(&st, req),
                (Method::Get, "/memo/stats") => handle_memo_stats(&st, req),
                (Method::Get, "/memo/drift") => handle_memo_drift(&st, req),
                (Method::Post, "/memo/probe-drift") => handle_memo_probe_drift(&st, req),
                (Method::Post, "/memo/clear") => handle_memo_clear(&st, req),
                (Method::Post, "/memo/selftest") => handle_memo_selftest(&st, req),
                _ => {
                    let _ = req.respond(error_response(
                        &format!("no route for {} {}", method, path_only),
                        404,
                    ));
                }
            }
        });
    }
}
